import type { Metadata } from "next"
import { RebookingFlow } from "./RebookingFlow"

export const metadata: Metadata = {
  title: "便の振替・再予約 | ANA",
  description: "欠航・遅延時の代替便への振替、または払戻しのお手続き",
}

// Server Component shell. 関数 prop を渡す UI はすべて RebookingFlow（"use client"）内に閉じる。
export default function FlightRebookingPage() {
  return (
    <main className="mx-auto min-h-dvh w-full max-w-[420px] bg-background text-foreground">
      <RebookingFlow />
    </main>
  )
}

"use client"

import * as React from "react"
import { IconChevronLeft, IconX } from "@tabler/icons-react"
import { cn } from "@gunjo/ui"

/**
 * ハンドロール: モバイル app-bar（戻る + タイトル + 右アクション）。
 * @gunjo/ui の Header は折り返す marketing バー（px-4 py-3, flex-wrap, justify-between）で
 * 戻るボタン/中央タイトルの app-bar 構造を持たないため、ここだけ自作。
 * 44px タップ領域・role/aria を満たす。
 */
export interface AppBarProps {
  title: string
  /** 戻る操作。先頭ステップでは undefined にしてボタンを隠す。 */
  onBack?: () => void
  /** 右上の閉じる/ヘルプ等。 */
  onClose?: () => void
  closeLabel?: string
}

export function AppBar({ title, onBack, onClose, closeLabel = "閉じる" }: AppBarProps) {
  return (
    <header
      className={cn(
        "sticky top-0 z-20 flex h-14 items-center gap-1 border-b border-border bg-background/95 px-1 backdrop-blur"
      )}
    >
      {onBack ? (
        <button
          type="button"
          onClick={onBack}
          aria-label="前の画面へ戻る"
          className="flex size-11 shrink-0 items-center justify-center rounded-full text-foreground transition-colors hover:bg-muted focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring"
        >
          <IconChevronLeft className="size-6" aria-hidden="true" />
        </button>
      ) : (
        <span className="size-11 shrink-0" aria-hidden="true" />
      )}

      <h1 className="min-w-0 flex-1 truncate text-center text-base font-semibold">{title}</h1>

      {onClose ? (
        <button
          type="button"
          onClick={onClose}
          aria-label={closeLabel}
          className="flex size-11 shrink-0 items-center justify-center rounded-full text-muted-foreground transition-colors hover:bg-muted focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring"
        >
          <IconX className="size-5" aria-hidden="true" />
        </button>
      ) : (
        <span className="size-11 shrink-0" aria-hidden="true" />
      )}
    </header>
  )
}

"use client"

import * as React from "react"
import {
  IconAlertTriangle,
  IconPlane,
  IconArrowRight,
  IconBed,
  IconToolsKitchen2,
  IconHeadset,
  IconCircleCheck,
  IconRefresh,
  IconCashBanknote,
} from "@tabler/icons-react"
import {
  cn,
  Alert,
  AlertTitle,
  AlertDescription,
  Button,
  Badge,
  Tag,
  Stepper,
  type StepperStep,
  RadioCardGroup,
  RadioCard,
  FilterChips,
  ToggleGroup,
  ToggleGroupItem,
  MetadataList,
  AmountBreakdown,
  Separator,
} from "@gunjo/ui"

import { AppBar } from "./AppBar"
import {
  original,
  disruption,
  altFlights,
  yenFmt,
  durationLabel,
  seatMeaning,
  type AltFlight,
  type Seat,
} from "./data"

type Step = "choose" | "select" | "confirm" | "done"
type Resolution = "rebook" | "refund"

const STEP_LABELS: Record<Step, string> = {
  choose: "対応の選択",
  select: "代替便の選択",
  confirm: "内容の確認",
  done: "完了",
}

function stepperSteps(active: Step): StepperStep[] {
  const order: Step[] = ["choose", "select", "confirm"]
  const activeIdx = active === "done" ? 3 : order.indexOf(active)
  return order.map((s, i) => ({
    label: STEP_LABELS[s],
    state: i < activeIdx ? "completed" : i === activeIdx ? "current" : "upcoming",
  }))
}

const seatTone: Record<Seat, "success" | "info" | "warning" | "destructive"> = {
  "◎": "success",
  "○": "info",
  "△": "warning",
  "×": "destructive",
}

/** 空席状況ピル（◎/○/△/×）— 色だけに依存しないよう記号と語を併記。 */
function SeatBadge({ seat }: { seat: Seat }) {
  const variant = seatTone[seat]
  return (
    <Badge variant={variant} aria-label={`空席 ${seatMeaning[seat]}`}>
      <span aria-hidden="true">{seat}</span>
      <span className="ml-0.5">{seatMeaning[seat]}</span>
    </Badge>
  )
}

function tagVariant(tag: AltFlight["tags"][number]) {
  switch (tag) {
    case "おすすめ":
      return "secondary" as const
    case "最短":
      return "default" as const
    case "他社便":
      return "outline" as const
    default:
      return "outline" as const
  }
}

/** 1便分のヘッダ表示（時刻・所要・経由）。RadioCard の description / 確認画面で再利用。 */
function FlightLine({ f }: { f: AltFlight }) {
  return (
    <span className="block">
      <span className="flex items-baseline gap-1.5 tabular-nums">
        <span className="text-lg font-bold text-foreground">{f.dep}</span>
        <span className="text-xs text-muted-foreground">{f.fromCode}</span>
        <IconArrowRight className="size-4 shrink-0 self-center text-muted-foreground" aria-hidden="true" />
        <span className="text-lg font-bold text-foreground">{f.arr}</span>
        <span className="text-xs text-muted-foreground">{f.toCode}</span>
      </span>
      <span className="mt-0.5 block text-xs text-muted-foreground">
        {f.via ? `${f.via} 経由` : "直行"}・所要 {durationLabel(f.durationMin)}・{f.cabin}
        {f.fromCode !== original.from.code ? `・${f.fromCode}発（別空港）` : ""}
      </span>
    </span>
  )
}

export function RebookingFlow() {
  const [step, setStep] = React.useState<Step>("choose")
  const [resolution, setResolution] = React.useState<Resolution | null>(null)
  const [selectedId, setSelectedId] = React.useState<string | null>(null)

  // 絞り込み: 当日/翌日 の単一選択（FilterChips）+ 直行のみ/他社便 の複数トグル（ToggleGroup）
  const [whenFilter, setWhenFilter] = React.useState<"all" | "today" | "tomorrow">("all")
  const [optionFilters, setOptionFilters] = React.useState<string[]>([])

  const selected = altFlights.find((f) => f.id === selectedId) ?? null

  const filtered = React.useMemo(() => {
    return altFlights.filter((f) => {
      if (whenFilter !== "all" && f.day !== whenFilter) return false
      if (optionFilters.includes("direct") && f.via !== null) return false
      if (optionFilters.includes("no-other") && f.otherAirline) return false
      return true
    })
  }, [whenFilter, optionFilters])

  const goRefund = () => {
    setResolution("refund")
    setSelectedId(null)
    setStep("confirm")
  }
  const goRebook = () => {
    setResolution("rebook")
    setStep("select")
  }

  const appBarTitle = STEP_LABELS[step]
  const onBack =
    step === "choose"
      ? undefined
      : step === "select"
        ? () => setStep("choose")
        : step === "confirm"
          ? () => setStep(resolution === "rebook" ? "select" : "choose")
          : undefined

  return (
    <div className="flex min-h-dvh flex-col">
      <AppBar title={appBarTitle} onBack={onBack} />

      {step !== "done" && (
        <div className="border-b border-border bg-card">
          <Stepper steps={stepperSteps(step)} aria-label="再予約の進行状況" className="py-3" />
        </div>
      )}

      <div className="flex-1 px-4 pb-28 pt-4">
        {step === "choose" && (
          <ChooseStep onRebook={goRebook} onRefund={goRefund} />
        )}
        {step === "select" && (
          <SelectStep
            selectedId={selectedId}
            onSelect={setSelectedId}
            whenFilter={whenFilter}
            onWhenChange={setWhenFilter}
            optionFilters={optionFilters}
            onOptionChange={setOptionFilters}
            filtered={filtered}
          />
        )}
        {step === "confirm" && (
          <ConfirmStep resolution={resolution} selected={selected} />
        )}
        {step === "done" && <DoneStep resolution={resolution} selected={selected} />}
      </div>

      {/* 固定フッタ CTA */}
      {step === "select" && (
        <FooterBar>
          <Button
            variant="primary"
            size="xl"
            className="w-full"
            disabled={!selectedId}
            onClick={() => setStep("confirm")}
          >
            {selected ? `${selected.flightNo} で確認へ進む` : "代替便を選んでください"}
          </Button>
        </FooterBar>
      )}
      {step === "confirm" && (
        <FooterBar>
          <Button
            variant={resolution === "refund" ? "destructive" : "primary"}
            size="xl"
            className="w-full"
            onClick={() => setStep("done")}
          >
            {resolution === "refund" ? "払戻しを確定する" : "この便に振り替える"}
          </Button>
        </FooterBar>
      )}
    </div>
  )
}

/* ---------- 固定フッタ ---------- */
function FooterBar({ children }: { children: React.ReactNode }) {
  return (
    <div className="fixed inset-x-0 bottom-0 z-20 mx-auto w-full max-w-[420px] border-t border-border bg-background/95 px-4 py-3 backdrop-blur [padding-bottom:calc(0.75rem+env(safe-area-inset-bottom))]">
      {children}
    </div>
  )
}

/* ---------- Step 1: 欠航通知 + 対応の選択 ---------- */
function ChooseStep({ onRebook, onRefund }: { onRebook: () => void; onRefund: () => void }) {
  return (
    <div className="space-y-4">
      {/* 欠航・遅延の通知（重要） — Alert(destructive)。Banner は1行truncate型なので不適。 */}
      <Alert variant="destructive">
        <IconAlertTriangle className="size-5 shrink-0" aria-hidden="true" />
        <AlertTitle as="h2" className="text-base">
          {original.flightNo} は{disruption.kind}になりました
        </AlertTitle>
        <AlertDescription>
          <span className="block">{disruption.detail}</span>
          <span className="mt-1 block text-xs opacity-80">
            理由: {disruption.reasonLabel}・{disruption.noticedAt}
          </span>
        </AlertDescription>
      </Alert>

      {/* 元の予約 */}
      <section aria-labelledby="orig-h" className="rounded-lg border border-border bg-card p-4">
        <div className="mb-3 flex items-center justify-between">
          <h2 id="orig-h" className="text-sm font-semibold text-muted-foreground">
            元のご予約
          </h2>
          <Tag variant="outline" size="sm">
            予約番号 {original.pnr}
          </Tag>
        </div>

        <div className="flex items-center gap-3">
          <span className="flex size-9 shrink-0 items-center justify-center rounded-full bg-muted">
            <IconPlane className="size-5 text-muted-foreground" aria-hidden="true" />
          </span>
          <div className="min-w-0">
            <p className="font-semibold">
              {original.flightNo}{" "}
              <span className="font-normal text-muted-foreground">{original.carrier}</span>
            </p>
            <p className="text-sm text-muted-foreground">{original.date}</p>
          </div>
        </div>

        <div className="mt-3 flex items-center gap-2 tabular-nums">
          <div>
            <p className="text-lg font-bold leading-tight line-through decoration-destructive/70">
              {original.schedDep}
            </p>
            <p className="text-xs text-muted-foreground">
              {original.from.code} {original.from.name}
            </p>
          </div>
          <IconArrowRight className="size-5 shrink-0 text-muted-foreground" aria-hidden="true" />
          <div>
            <p className="text-lg font-bold leading-tight line-through decoration-destructive/70">
              {original.schedArr}
            </p>
            <p className="text-xs text-muted-foreground">
              {original.to.code} {original.to.name}
            </p>
          </div>
          <Badge variant="destructive" className="ml-auto">
            {disruption.kind}
          </Badge>
        </div>

        <Separator className="my-3" />
        <MetadataList
          variant="compact"
          layout="horizontal"
          items={[
            { label: "搭乗クラス", value: original.cabin },
            { label: "搭乗者", value: original.passengers.join("・") },
          ]}
        />
      </section>

      {/* 対応の選択 */}
      <section aria-labelledby="choose-h" className="space-y-2">
        <h2 id="choose-h" className="text-sm font-semibold">
          ご対応をお選びください
        </h2>
        <button
          type="button"
          onClick={onRebook}
          className="flex w-full items-center gap-3 rounded-lg border border-border bg-card p-4 text-left transition-colors hover:border-primary/60 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring"
        >
          <span className="flex size-10 shrink-0 items-center justify-center rounded-full bg-primary/10 text-primary-strong">
            <IconRefresh className="size-5" aria-hidden="true" />
          </span>
          <span className="min-w-0 flex-1">
            <span className="block font-semibold">代替便に振り替える</span>
            <span className="block text-sm text-muted-foreground">
              当日中・翌日の代替便から選べます。差額なしの便あり
            </span>
          </span>
          <IconArrowRight className="size-5 shrink-0 text-muted-foreground" aria-hidden="true" />
        </button>

        <button
          type="button"
          onClick={onRefund}
          className="flex w-full items-center gap-3 rounded-lg border border-border bg-card p-4 text-left transition-colors hover:border-primary/60 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring"
        >
          <span className="flex size-10 shrink-0 items-center justify-center rounded-full bg-muted text-foreground">
            <IconCashBanknote className="size-5" aria-hidden="true" />
          </span>
          <span className="min-w-0 flex-1">
            <span className="block font-semibold">全額払戻しを受ける</span>
            <span className="block text-sm text-muted-foreground">
              旅行を取りやめる場合。手数料なしで全額返金
            </span>
          </span>
          <IconArrowRight className="size-5 shrink-0 text-muted-foreground" aria-hidden="true" />
        </button>
      </section>

      <CompensationNote />
    </div>
  )
}

/* ---------- Step 2: 絞り込み + 代替便候補の選択 ---------- */
function SelectStep({
  selectedId,
  onSelect,
  whenFilter,
  onWhenChange,
  optionFilters,
  onOptionChange,
  filtered,
}: {
  selectedId: string | null
  onSelect: (id: string) => void
  whenFilter: "all" | "today" | "tomorrow"
  onWhenChange: (v: "all" | "today" | "tomorrow") => void
  optionFilters: string[]
  onOptionChange: (v: string[]) => void
  filtered: AltFlight[]
}) {
  return (
    <div className="space-y-3">
      <div className="flex items-center justify-between">
        <p className="text-sm text-muted-foreground">
          {original.from.code} → {original.to.code} の代替便
        </p>
        <span className="text-sm font-medium tabular-nums">{filtered.length}件</span>
      </div>

      {/* 絞り込み: いつ（単一） */}
      <FilterChips
        aria-label="出発のタイミングで絞り込み"
        value={whenFilter}
        onValueChange={(v) => onWhenChange(v as "all" | "today" | "tomorrow")}
        items={[
          { value: "all", label: "すべて" },
          { value: "today", label: "当日中" },
          { value: "tomorrow", label: "翌日" },
        ]}
      />

      {/* 絞り込み: 条件（複数トグル） */}
      <ToggleGroup
        type="multiple"
        variant="outline"
        size="sm"
        value={optionFilters}
        onValueChange={(v) => onOptionChange(v as string[])}
        className="justify-start gap-2"
        aria-label="便の条件で絞り込み"
      >
        <ToggleGroupItem value="direct" aria-label="直行便のみ" className="rounded-full px-3">
          直行のみ
        </ToggleGroupItem>
        <ToggleGroupItem value="no-other" aria-label="自社便のみ（他社便を除く）" className="rounded-full px-3">
          自社便のみ
        </ToggleGroupItem>
      </ToggleGroup>

      <Separator />

      {/* 代替便候補（pick-one）— RadioCard */}
      {filtered.length === 0 ? (
        <Alert variant="info">
          <AlertTitle>条件に合う便がありません</AlertTitle>
          <AlertDescription>絞り込みを変更してお試しください。</AlertDescription>
        </Alert>
      ) : (
        <RadioCardGroup
          value={selectedId ?? ""}
          onValueChange={onSelect}
          aria-label="代替便を1つ選択"
          name="alt-flight"
          className="gap-2.5"
        >
          {filtered.map((f) => (
            <RadioCard
              key={f.id}
              value={f.id}
              tags={
                <>
                  {f.tags.map((t) => (
                    <Tag key={t} variant={tagVariant(t)} size="sm">
                      {t}
                    </Tag>
                  ))}
                  <Tag variant="outline" size="sm">
                    {f.carrierShort}
                  </Tag>
                </>
              }
              title={
                <span className="flex items-center gap-2">
                  <span>{f.flightNo}</span>
                  <SeatBadge seat={f.seat} />
                </span>
              }
              description={<FlightLine f={f} />}
              price={
                f.fareDiff === 0 ? (
                  <span className="text-success-strong">差額なし</span>
                ) : (
                  <span>+¥{yenFmt.format(f.fareDiff)}</span>
                )
              }
              highlight={
                f.fareDiff === 0 ? "追加のお支払いはありません" : "差額のお支払いが必要です"
              }
            />
          ))}
        </RadioCardGroup>
      )}
    </div>
  )
}

/* ---------- Step 3: 確認 ---------- */
function ConfirmStep({
  resolution,
  selected,
}: {
  resolution: Resolution | null
  selected: AltFlight | null
}) {
  if (resolution === "refund") {
    return (
      <div className="space-y-4">
        <Alert variant="info">
          <AlertTitle>全額払戻しの確認</AlertTitle>
          <AlertDescription>
            {original.flightNo}（{original.date}）のご予約を取り消し、全額を払い戻します。
          </AlertDescription>
        </Alert>

        <section className="rounded-lg border border-border bg-card p-4">
          <h2 className="mb-3 text-sm font-semibold text-muted-foreground">払戻し内容</h2>
          <MetadataList
            items={[
              { label: "予約番号", value: original.pnr },
              { label: "対象便", value: `${original.flightNo} ${original.from.code}→${original.to.code}` },
              { label: "搭乗者", value: original.passengers.join("・") },
              { label: "払戻し先", value: "ご予約時のクレジットカード" },
            ]}
          />
          <Separator className="my-3" />
          <AmountBreakdown
            lines={[
              { label: "運賃（2名分）", amount: 84000 },
              { label: "取消手数料（欠航のため）", amount: 0, kind: "subtract" },
            ]}
            total={{ label: "払戻し額", amount: 84000, tone: "positive" }}
            formula="払戻し額 = 運賃 − 取消手数料"
          />
        </section>
        <CompensationNote />
      </div>
    )
  }

  if (!selected) {
    return (
      <Alert variant="warning">
        <AlertTitle>代替便が選択されていません</AlertTitle>
        <AlertDescription>前の画面に戻って代替便をお選びください。</AlertDescription>
      </Alert>
    )
  }

  return (
    <div className="space-y-4">
      <p className="text-sm text-muted-foreground">以下の内容で振り替えます。よろしければ確定してください。</p>

      {/* Before → After */}
      <section className="space-y-2">
        <div className="rounded-lg border border-border bg-muted/40 p-3">
          <p className="mb-1 text-xs font-medium text-muted-foreground">変更前（欠航）</p>
          <p className="font-semibold tabular-nums line-through decoration-destructive/70">
            {original.flightNo}・{original.schedDep}→{original.schedArr}
          </p>
        </div>
        <div className="flex justify-center text-muted-foreground" aria-hidden="true">
          <IconArrowRight className="size-5 rotate-90" />
        </div>
        <div className="rounded-lg border border-primary bg-primary/5 p-4">
          <p className="mb-2 flex items-center gap-2 text-xs font-medium text-primary-strong">
            変更後（振替）
            <SeatBadge seat={selected.seat} />
          </p>
          <p className="text-base font-bold">
            {selected.flightNo}{" "}
            <span className="font-normal text-muted-foreground">{selected.carrier}</span>
          </p>
          <div className="mt-1">
            <FlightLine f={selected} />
          </div>
        </div>
      </section>

      <section className="rounded-lg border border-border bg-card p-4">
        <h2 className="mb-3 text-sm font-semibold text-muted-foreground">搭乗者・差額</h2>
        <MetadataList
          items={[
            { label: "搭乗者", value: original.passengers.join("・") },
            { label: "予約番号", value: original.pnr },
          ]}
        />
        <Separator className="my-3" />
        <AmountBreakdown
          lines={[
            {
              label: "振替差額",
              amount: selected.fareDiff * original.passengers.length,
              note:
                selected.fareDiff === 0
                  ? "差額なしの便です"
                  : `¥${yenFmt.format(selected.fareDiff)} × ${original.passengers.length}名`,
            },
          ]}
          total={{
            label: "お支払い差額",
            amount: selected.fareDiff * original.passengers.length,
            tone: selected.fareDiff === 0 ? "neutral" : "negative",
          }}
        />
        {selected.fareDiff === 0 && (
          <p className="mt-2 text-sm font-medium text-success-strong">追加のお支払いはありません。</p>
        )}
      </section>

      {selected.otherAirline && (
        <Alert variant="warning">
          <AlertTitle>他社便への振替です</AlertTitle>
          <AlertDescription>
            運航は {selected.carrier} です。手荷物規定が異なる場合があります。
          </AlertDescription>
        </Alert>
      )}
    </div>
  )
}

/* ---------- Step 4: 完了 ---------- */
function DoneStep({ resolution, selected }: { resolution: Resolution | null; selected: AltFlight | null }) {
  return (
    <div className="space-y-5 pt-6 text-center">
      <span className="mx-auto flex size-16 items-center justify-center rounded-full bg-success-subtle text-success-strong">
        <IconCircleCheck className="size-9" aria-hidden="true" />
      </span>
      <div>
        <h2 className="text-xl font-bold">
          {resolution === "refund" ? "払戻しを受け付けました" : "振替が完了しました"}
        </h2>
        <p className="mt-1 text-sm text-muted-foreground">
          {resolution === "refund"
            ? "5〜7営業日でカードへ返金されます。"
            : "新しい搭乗券を発行しました。メールでもお送りしています。"}
        </p>
      </div>

      {resolution === "rebook" && selected && (
        <section className="rounded-lg border border-primary bg-primary/5 p-4 text-left">
          <p className="text-base font-bold">{selected.flightNo}</p>
          <div className="mt-1">
            <FlightLine f={selected} />
          </div>
          <Separator className="my-3" />
          <MetadataList
            variant="compact"
            items={[
              { label: "予約番号", value: original.pnr },
              { label: "搭乗者", value: original.passengers.join("・") },
            ]}
          />
        </section>
      )}

      <CompensationNote />
    </div>
  )
}

